```class Solution {
public:
    long long maximumOr(vector<int>& nums, int k) {
        priority_queue<int, vector<int>, greater<int>> pq(nums.begin(), nums.end());
        while (k--) {
            int x = pq.top();
            pq.pop();
            pq.push(x * 2);
        }
        long long res = 0;
        while (!pq.empty()) {
            res |= pq.top();
            pq.pop();
        }
        return res;
    }
};
